class TemplatesManager {
    constructor() {
        this.grid = document.getElementById('templates-grid');
        this.createBtn = document.getElementById('create-template-btn');
        this.exportBtn = document.getElementById('export-templates-btn');
        this.importBtn = document.getElementById('import-templates-btn');
        this.deleteAllBtn = document.getElementById('delete-all-custom-templates-btn');
        this.importInput = document.getElementById('import-templates-input');

        this.customTemplates = Storage.getJSON('custom-templates', []);

        // Ensure activeTemplateId exists and is valid, defaulting to 'classic'
        this.activeTemplateId = Storage.get('activeTemplateId');
        if (!this.activeTemplateId) {
            this.activeTemplateId = 'classic';
            Storage.set('activeTemplateId', 'classic');
        } else {
            // Check if it still exists
            const all = this.getAllTemplates();
            if (!all.find(t => t.id === this.activeTemplateId)) {
                this.activeTemplateId = 'classic';
                Storage.set('activeTemplateId', 'classic');
            }
        }

        if (this.grid) {
            this.render();
            this.bindEvents();
        }
    }

    bindEvents() {
        this.createBtn?.addEventListener('click', () => this.createTemplate());
        this.exportBtn?.addEventListener('click', () => this.exportTemplates());
        this.importBtn?.addEventListener('click', () => this.importInput?.click());
        this.deleteAllBtn?.addEventListener('click', () => this.deleteAllCustomTemplates());
        this.importInput?.addEventListener('change', (e) => this.importTemplates(e));
    }

    async deleteAllCustomTemplates() {
        if (this.customTemplates.length === 0) return;

        await i18n.loadTranslations();
        
        const modal = document.getElementById('confirmar-eliminar-plantilla');
        const titleEl = document.getElementById('eliminar-plantilla-titulo');
        const msgEl = document.getElementById('eliminar-plantilla-mensaje');
        const confirmBtn = document.getElementById('confirmar-eliminar-tpl-btn');
        const cancelBtn = document.getElementById('cancelar-eliminar-tpl-btn');

        if (!modal || !msgEl || !confirmBtn || !cancelBtn) {
            if (confirm(i18n.translate('delete-all-custom-templates-msg'))) {
                this._executeDeleteAll();
            }
            return;
        }

        // Translate and set content
        if (titleEl) titleEl.textContent = i18n.translate('delete-all-custom-templates');
        msgEl.textContent = i18n.translate('delete-all-custom-templates-msg');
        confirmBtn.textContent = i18n.translate('delete-all-custom-templates-confirm');
        cancelBtn.textContent = i18n.translate('delete-template-cancel');

        modal.style.display = 'flex';

        // Clean previous listeners
        const newConfirmBtn = confirmBtn.cloneNode(true);
        confirmBtn.parentNode.replaceChild(newConfirmBtn, confirmBtn);

        const newCancelBtn = cancelBtn.cloneNode(true);
        cancelBtn.parentNode.replaceChild(newCancelBtn, cancelBtn);

        newConfirmBtn.addEventListener('click', () => {
            modal.style.display = 'none';
            this._executeDeleteAll();
        });

        newCancelBtn.addEventListener('click', () => {
            modal.style.display = 'none';
        });

        modal.onclick = (e) => {
            if (e.target === modal) modal.style.display = 'none';
        };
    }

    _executeDeleteAll() {
        this.customTemplates = [];
        Storage.setJSON('custom-templates', this.customTemplates);
        
        // If active template was custom, reset to classic
        if (this.activeTemplateId && this.activeTemplateId.startsWith('custom_')) {
            this.activeTemplateId = 'classic';
            Storage.set('activeTemplateId', 'classic');
        }
        
        this.render();
    }

    getAllTemplates() {
        return [...DEFAULT_TEMPLATES, ...this.customTemplates];
    }

    render() {
        this.grid.innerHTML = '';
        
        // Show/hide delete all button
        if (this.deleteAllBtn) {
            this.deleteAllBtn.style.display = this.customTemplates.length > 0 ? 'inline-flex' : 'none';
        }

        this.getAllTemplates().forEach(template => {
            const card = document.createElement('div');
            card.className = 'template-card';

            const isGif = template.bgUrl && template.bgUrl.toLowerCase().endsWith('.gif');

            const imgContainer = document.createElement('div');
            imgContainer.className = 'template-img-container';

            if (isGif) {
                // For GIFs: render first frame on a canvas (paused)
                // and only show the animated GIF on hover
                const canvas = document.createElement('canvas');
                canvas.className = 'template-preview template-preview-static';
                canvas.alt = template.name;

                const gifImg = document.createElement('img');
                gifImg.className = 'template-preview template-preview-gif';
                gifImg.alt = template.name;
                // Don't set src yet to avoid loading the GIF until needed
                gifImg.dataset.gifSrc = template.bgUrl;

                // Load the GIF once to capture the first frame
                const tempImg = new Image();
                tempImg.crossOrigin = 'anonymous';
                tempImg.onload = function () {
                    canvas.width = tempImg.naturalWidth;
                    canvas.height = tempImg.naturalHeight;
                    const ctx = canvas.getContext('2d');
                    ctx.drawImage(tempImg, 0, 0);
                    // Remove temp image from memory
                    tempImg.src = '';
                };
                tempImg.onerror = function () {
                    // Fallback: try PNG version
                    const fallbackSrc = template.bgUrl.replace(/\.gif$/i, '.png');
                    const fallbackImg = new Image();
                    fallbackImg.onload = function () {
                        canvas.width = fallbackImg.naturalWidth;
                        canvas.height = fallbackImg.naturalHeight;
                        const ctx = canvas.getContext('2d');
                        ctx.drawImage(fallbackImg, 0, 0);
                    };
                    fallbackImg.src = fallbackSrc;
                };
                tempImg.src = template.bgUrl;

                // On hover: load and show the animated GIF
                imgContainer.addEventListener('mouseenter', () => {
                    if (!gifImg.src || gifImg.src === '' || gifImg.src === window.location.href) {
                        gifImg.src = gifImg.dataset.gifSrc;
                    }
                });

                imgContainer.appendChild(canvas);
                imgContainer.appendChild(gifImg);

                // Add GIF / video icon badge
                const gifBadge = document.createElement('div');
                gifBadge.className = 'template-gif-badge';
                gifBadge.innerHTML = '<i class="fa-solid fa-play"></i>';
                gifBadge.title = 'GIF animado';
                imgContainer.appendChild(gifBadge);

                // Mark the card as a GIF card for CSS hover behavior
                card.classList.add('template-card-gif');
            } else {
                const img = document.createElement('img');
                img.src = template.bgUrl;
                img.alt = template.name;
                img.className = 'template-preview';

                img.onerror = function () {
                    if (this.src.endsWith('.gif')) {
                        this.src = this.src.replace('.gif', '.png');
                    }
                };

                imgContainer.appendChild(img);
            }

            if (template.isCustom) {
                const deleteBtn = document.createElement('button');
                deleteBtn.className = 'template-delete-btn';
                deleteBtn.innerHTML = '<i class="fa-solid fa-trash"></i>';
                deleteBtn.title = 'Eliminar plantilla';
                deleteBtn.onclick = (e) => {
                    e.stopPropagation();
                    this.deleteTemplate(template.id);
                };
                imgContainer.appendChild(deleteBtn);
            }

            const name = document.createElement('div');
            name.className = 'template-name fuente-aplicada';
            name.textContent = template.name;

            card.appendChild(imgContainer);
            card.appendChild(name);

            if (template.id === this.activeTemplateId) {
                card.classList.add('template-card-active');
            }

            card.addEventListener('click', () => {
                this.applyTemplate(template);
            });

            this.grid.appendChild(card);
        });
    }

    async createTemplate() {
        await i18n.loadTranslations();
        const modal = document.getElementById('modal-crear-plantilla');
        const input = document.getElementById('nuevo-template-nombre');
        const confirmBtn = document.getElementById('confirmar-crear-tpl-btn');
        const cancelBtn = document.getElementById('cancelar-crear-tpl-btn');

        if (!modal || !input || !confirmBtn || !cancelBtn) {
            // Fallback
            const name = prompt(i18n.translate('create-template-title'));
            if (name) this._saveNewTemplate(name);
            return;
        }

        input.value = '';

        // Translate labels manually to ensure they are immediate
        const titleEl = modal.querySelector('h3');
        const labelEl = modal.querySelector('label');
        if (titleEl) titleEl.textContent = i18n.translate('create-template-title');
        if (labelEl) labelEl.textContent = i18n.translate('create-template-label');
        input.placeholder = i18n.translate('create-template-placeholder');
        confirmBtn.textContent = i18n.translate('create-template-confirm');
        cancelBtn.textContent = i18n.translate('create-template-cancel');

        modal.style.display = 'flex';
        input.focus();

        // Clean previous listeners
        const newConfirmBtn = confirmBtn.cloneNode(true);
        confirmBtn.parentNode.replaceChild(newConfirmBtn, confirmBtn);

        const newCancelBtn = cancelBtn.cloneNode(true);
        cancelBtn.parentNode.replaceChild(newCancelBtn, cancelBtn);

        const doCreate = () => {
            const name = input.value.trim();
            if (name) {
                modal.style.display = 'none';
                this._saveNewTemplate(name);
            }
        };

        newConfirmBtn.addEventListener('click', doCreate);
        newCancelBtn.addEventListener('click', () => modal.style.display = 'none');

        input.onkeydown = (e) => {
            if (e.key === 'Enter') doCreate();
            if (e.key === 'Escape') modal.style.display = 'none';
        };

        modal.onclick = (e) => {
            if (e.target === modal) modal.style.display = 'none';
        };
    }

    _saveNewTemplate(name) {
        const currentLayout = Storage.getJSON('widgetLayout', {});
        const currentBg = Storage.get('fondo-url') || 'fondos/background1.png';
        const currentColor = Storage.get('colorBotones') || '#b3336b';

        const newTemplate = {
            id: 'custom_' + Date.now(),
            name: name,
            bgUrl: currentBg,
            color: currentColor,
            layout: currentLayout,
            isCustom: true
        };

        this.customTemplates.push(newTemplate);
        Storage.setJSON('custom-templates', this.customTemplates);
        Storage.set('activeTemplateId', newTemplate.id);
        this.activeTemplateId = newTemplate.id;
        this.render();
    }

    async deleteTemplate(id) {
        await i18n.loadTranslations();
        const template = this.customTemplates.find(t => t.id === id);
        if (!template) return;

        const modal = document.getElementById('confirmar-eliminar-plantilla');
        const titleEl = document.getElementById('eliminar-plantilla-titulo');
        const msgEl = document.getElementById('eliminar-plantilla-mensaje');
        const confirmBtn = document.getElementById('confirmar-eliminar-tpl-btn');
        const cancelBtn = document.getElementById('cancelar-eliminar-tpl-btn');

        if (!modal || !msgEl || !confirmBtn || !cancelBtn) {
            // Fallback
            if (confirm(i18n.translate('delete-template-msg').replace('{name}', template.name))) {
                this._executeDelete(id);
            }
            return;
        }

        // Translate and set content
        if (titleEl) titleEl.textContent = i18n.translate('delete-template-title');
        msgEl.textContent = i18n.translate('delete-template-msg').replace('{name}', template.name);
        confirmBtn.textContent = i18n.translate('delete-template-confirm');
        cancelBtn.textContent = i18n.translate('delete-template-cancel');

        modal.style.display = 'flex';

        // Clean previous listeners
        const newConfirmBtn = confirmBtn.cloneNode(true);
        confirmBtn.parentNode.replaceChild(newConfirmBtn, confirmBtn);

        const newCancelBtn = cancelBtn.cloneNode(true);
        cancelBtn.parentNode.replaceChild(newCancelBtn, cancelBtn);

        newConfirmBtn.addEventListener('click', () => {
            modal.style.display = 'none';
            this._executeDelete(id);
        });

        newCancelBtn.addEventListener('click', () => {
            modal.style.display = 'none';
        });

        modal.onclick = (e) => {
            if (e.target === modal) modal.style.display = 'none';
        };
    }

    _executeDelete(id) {
        this.customTemplates = this.customTemplates.filter(t => t.id !== id);
        Storage.setJSON('custom-templates', this.customTemplates);
        this.render();
    }

    exportTemplates() {
        if (this.customTemplates.length === 0) {
            alert("No tienes plantillas personalizadas para exportar.");
            return;
        }
        const data = JSON.stringify(this.customTemplates, null, 2);
        const blob = new Blob([data], { type: 'application/json' });
        const url = URL.createObjectURL(blob);
        const a = document.createElement('a');
        a.href = url;
        a.download = `temas-personalizados-${new Date().toISOString().split('T')[0]}.json`;
        a.click();
        URL.revokeObjectURL(url);
    }

    importTemplates(event) {
        const file = event.target.files[0];
        if (!file) return;

        const reader = new FileReader();
        reader.onload = (e) => {
            try {
                const imported = JSON.parse(e.target.result);
                if (!Array.isArray(imported)) {
                    throw new Error("Invalid format, expected array of templates");
                }

                // Add isCustom tag and regenerate IDs
                const newTemplates = imported.map(t => ({
                    ...t,
                    id: 'custom_' + Date.now() + Math.random().toString(36).substr(2, 9),
                    isCustom: true
                }));

                this.customTemplates = [...this.customTemplates, ...newTemplates];
                Storage.setJSON('custom-templates', this.customTemplates);
                this.render();

                event.target.value = '';
                alert("Plantillas importadas con éxito.");
            } catch (err) {
                console.error("Error al importar plantillas:", err);
                alert("Error: El archivo no es un formato de plantillas válido.");
            }
        };
        reader.readAsText(file);
    }

    async applyTemplate(template) {
        await i18n.loadTranslations();
        const modal = document.getElementById('confirmar-aplicar-plantilla');
        const titleEl = document.getElementById('aplicar-plantilla-titulo');
        const msgEl = document.getElementById('aplicar-plantilla-mensaje');
        const confirmBtn = document.getElementById('confirmar-aplicar-btn');
        const cancelBtn = document.getElementById('cancelar-aplicar-btn');

        if (!modal || !msgEl || !confirmBtn || !cancelBtn) {
            // Fallback if elements not found
            if (confirm(i18n.translate('apply-template-msg').replace('{name}', template.name))) {
                this._executeApply(template);
            }
            return;
        }

        // Translate and set content
        if (titleEl) titleEl.textContent = i18n.translate('apply-template-title');
        msgEl.textContent = i18n.translate('apply-template-msg').replace('{name}', template.name);
        confirmBtn.textContent = i18n.translate('apply-template-confirm');
        cancelBtn.textContent = i18n.translate('apply-template-cancel');

        modal.style.display = 'flex';

        // Clean previous listeners
        const newConfirmBtn = confirmBtn.cloneNode(true);
        confirmBtn.parentNode.replaceChild(newConfirmBtn, confirmBtn);

        const newCancelBtn = cancelBtn.cloneNode(true);
        cancelBtn.parentNode.replaceChild(newCancelBtn, cancelBtn);

        newConfirmBtn.addEventListener('click', () => {
            modal.style.display = 'none';
            this._executeApply(template);
        });

        newCancelBtn.addEventListener('click', () => {
            modal.style.display = 'none';
        });

        // Close on clicking outside the card
        modal.onclick = (e) => {
            if (e.target === modal) modal.style.display = 'none';
        };
    }

    _executeApply(template) {
        Storage.setJSON('widgetLayout', template.layout);
        Storage.set('fondo-url', template.bgUrl);
        if (template.color) {
            Storage.set('colorBotones', template.color);
        }
        if (template.font) {
            Storage.set('fuente-pagina', template.font);
        }
        Storage.set('activeTemplateId', template.id);
        location.reload();
    }

    // New logic to fork current state into a new template on modification
    handleModification() {
        // Prevent forking multiple times rapidly
        if (this._forkingThrottle) {
            clearTimeout(this._forkingThrottle);
        }
        this._forkingThrottle = setTimeout(() => this._doFork(), 1000);
    }

    _doFork() {
        const allTemplates = this.getAllTemplates();
        const currentActive = allTemplates.find(t => t.id === this.activeTemplateId);

        if (!currentActive) return;

        const currentLayout = Storage.getJSON('widgetLayout', {});
        const currentBg = Storage.get('fondo-url') || (currentActive.bgUrl || '');
        const currentColor = Storage.get('colorBotones') || (currentActive.color || '');
        const currentFont = Storage.get('fuente-pagina') || (currentActive.font || '');

        // Check if anything actually changed compared to the active template
        const layoutChanged = JSON.stringify(currentLayout) !== JSON.stringify(currentActive.layout);
        const bgChanged = currentBg !== currentActive.bgUrl;
        const colorChanged = currentColor !== currentActive.color;
        const fontChanged = currentFont !== currentActive.font;

        if (!layoutChanged && !bgChanged && !colorChanged && !fontChanged) {
            return; // No change, no need to fork
        }

        if (currentActive.isCustom) {
            // Update the existing custom template instead of creating a new one
            currentActive.layout = currentLayout;
            currentActive.bgUrl = currentBg;
            currentActive.color = currentColor;
            currentActive.font = currentFont;

            Storage.setJSON('custom-templates', this.customTemplates);
            console.log(`Updated existing custom template ${currentActive.id}`);
        } else {
            // Fork into a new custom template
            const newId = 'custom_' + Date.now();
            const newName = `Mi ${currentActive.name}`;

            const newTemplate = {
                id: newId,
                name: newName,
                bgUrl: currentBg,
                color: currentColor,
                font: currentFont,
                layout: currentLayout,
                isCustom: true
            };

            this.customTemplates.push(newTemplate);
            Storage.setJSON('custom-templates', this.customTemplates);
            Storage.set('activeTemplateId', newId);
            this.activeTemplateId = newId;

            console.log(`Auto-forked template ${currentActive.id} into ${newId}`);
        }

        if (this.grid) {
            this.render();
        }
    }
}

export const templatesManager = new TemplatesManager();
